+    #[test]
+    fn flowchart_click_directive_blocks_protocol_relative_links() {
+        let parsed = parse_mermaid("flowchart LR\nA-->B\nclick A \"//example.com\"");
+        assert!(
+            parsed
+                .warnings
+                .iter()
+                .any(|warning| warning.contains("unsafe click link target blocked"))
